const query = $json.query;

if (query['hub.verify_token'] === 'MEU_TOKEN_SECRETO') {
  return [
    {
      json: {
        challenge: query['hub.challenge']
      }
    }
  ];
}

return [
  {
    json: {
      error: 'Token inválido'
    }
  }
];

const message1 = $json.Message1;
const message2 = $json.Message2;

// Compara os arrays convertendo para string
const saoIguais = JSON.stringify(message1) === JSON.stringify(message2);

if (!saoIguais) {
  // Mensagens diferentes - retorna false
  return [{
    json: {
      resultado: false
    }
  }];
}

// Mensagens iguais - retorna a mensagem
return [{
  json: {
    mensagem: message1[0],
    resultado: true
  }
}];

const raw = ($('AI Agent').first().json.output || "").replace(/\r/g, "");

const isBullet = (s) => /^\s*(?:[-*•·]|[0-9]+\.)\s+/.test(s);
const isBlank  = (s) => /^\s*$/.test(s);

const lines = raw.split("\n");

const groups = [];
let buf = [];
let mode = null;

const flush = () => {
  if (!buf.length) return;
  const text = mode === "bullets" ? buf.join("\n") : buf.join(" ").replace(/\s{2,}/g, " ");
  groups.push(text);
  buf = [];
  mode = null;
};

for (let i = 0; i < lines.length; i++) {
  const lineRaw = lines[i];
  const line = lineRaw.trim();

  if (isBlank(lineRaw)) {
    flush();
    continue;
  }

  if (isBullet(line)) {
    if (mode !== "bullets") flush();
    mode = "bullets";
    buf.push(lineRaw.trim()); 
  } else {
    if (mode === "bullets") flush();
    mode = "para";
    buf.push(line);
  }
}
flush();


const MAX = 1200;
const out = [];
for (const g of groups) {
  let s = g;
  while (s.length > MAX) {
    const cutAt = Math.max(s.lastIndexOf("\n", MAX), s.lastIndexOf(". ", MAX), s.lastIndexOf(" ", MAX));
    const idx = cutAt > 200 ? cutAt : MAX;
    out.push({ result: s.slice(0, idx).trim() });
    s = s.slice(idx).trimStart();
  }
  out.push({ result: s });
}

return out;

const results = [];
const items = $input.all();

for (let i = 0; i < items.length; i++) {
  const data = items[i].json;

  if (data && data.payload && Array.isArray(data.payload)) {
    for (let j = 0; j < data.payload.length; j++) {
      const conversa = data.payload[j];

      if (conversa.inbox_id === 26) {
        results.push({ json: conversa });
      }
    }
  }
}

return results.length > 0 ? results : [];
